from flask import Flask, request, jsonify
import psycopg2

app = Flask(__name__)

# Replace these with your actual database credentials and name
DB_HOST = 'localhost'
DB_NAME = 'your_database_name'
DB_USER = 'your_username'
DB_PASSWORD = 'your_password'

def build_sql_query(table_name, columns=None, filters=None):
    query = f"SELECT {', '.join(columns or '*')} FROM {table_name}"
    
    if filters:
        conditions = [f"{column} = '{value}'" for column, value in filters.items()]
        query += " WHERE " + " AND ".join(conditions)
        
    return query

def execute_query(query):
    conn = psycopg2.connect(
        dbname=DB_NAME,
        user=DB_USER,
        password=DB_PASSWORD,
        host=DB_HOST
    )
    
    cur = conn.cursor()
    cur.execute(query)
    
    rows = cur.fetchall()
    
    conn.close()
    
    return rows

@app.route('/api/query', methods=['POST'])
def query_database():
    data = request.json
    
    table_name = data.get('table')
    columns = data.get('columns')
    filters = data.get('filters')
    
    if not all([table_name, columns, filters]):
        return jsonify({'error': 'Missing required parameters'}), 400
    
    query = build_sql_query(table_name=table_name, columns=columns, filters=filters)
    
    rows = execute_query(query)
    
    return jsonify(rows)

if __name__ == '__main__':
    app.run(debug=True)